var roomTemp = flow.get('roomTemp') || 18;
var flowTemp = flow.get('flowTemp') || 30;
var valveOutput = flow.get('valve') || 0;
var outsideTemp = flow.get('outside') || 5;

var flowHeatGain = valveOutput * 0.8;
var flowHeatLoss = (flowTemp - 20) * 0.3;
flowTemp = flowTemp + flowHeatGain - flowHeatLoss;
flowTemp = Math.max(20, Math.min(80, flowTemp));

var roomHeatGain = (flowTemp - roomTemp) * 0.02;
var roomHeatLoss = (roomTemp - outsideTemp) * 0.015;
roomTemp = roomTemp + roomHeatGain - roomHeatLoss;

roomTemp += (Math.random() - 0.5) * 0.1;
flowTemp += (Math.random() - 0.5) * 0.2;

flow.set('roomTemp', roomTemp);
flow.set('flowTemp', flowTemp);

msg.payload = Math.round(roomTemp * 10) / 10;
msg.flowTemp = Math.round(flowTemp * 10) / 10;

var innerOutput = flow.get('innerOutput');
if (innerOutput !== undefined) {
    msg.trackingValue = innerOutput;
}

return msg;

var flowSP = msg.payload;
var flowPV = flow.get('flowTemp') || 30;
flow.set('flowSP', flowSP);
msg.setpoint = flowSP;
msg.payload = flowPV;
return msg;

flow.set('valve', msg.payload);
flow.set('innerOutput', msg.payload);
return msg;
